sql_examples.sql:
-- 1. 데이터베이스 종료
SHUTDOWN IMMEDIATE;

-- 2. OS 레벨에서 파일 복사 (SQL*Plus 외부에서 실행)
-- $ cp /u01/oradata/orcl26ai/system01.dbf /u02/oradata/orcl26ai/system01.dbf

-- 3. MOUNT 상태로 기동
STARTUP MOUNT;

-- 4. 컨트롤 파일의 경로 정보 갱신
ALTER DATABASE RENAME FILE
  '/u01/oradata/orcl26ai/system01.dbf'
  TO '/u02/oradata/orcl26ai/system01.dbf';

-- 5. 데이터베이스 오픈
ALTER DATABASE OPEN;

-- 6. 변경 확인
SELECT file_name FROM dba_data_files
WHERE tablespace_name = 'SYSTEM';

-- 1. 테이블스페이스 오프라인
ALTER TABLESPACE users OFFLINE;

-- 2. OS 레벨에서 파일 복사 (SQL*Plus 외부에서 실행)
-- $ cp /u01/oradata/orcl26ai/users01.dbf /u02/oradata/orcl26ai/users01.dbf

-- 3. 경로 갱신
ALTER TABLESPACE users RENAME DATAFILE
  '/u01/oradata/orcl26ai/users01.dbf'
  TO '/u02/oradata/orcl26ai/users01.dbf';

-- 4. 테이블스페이스 온라인
ALTER TABLESPACE users ONLINE;

-- 5. 확인
SELECT file_name, status FROM dba_data_files
WHERE tablespace_name = 'USERS';

-- 표준 블록 사이즈 확인
SHOW PARAMETER db_block_size;

-- 버퍼 캐시 크기 확인
SHOW PARAMETER db_cache_size;

-- 현재 SGA 내 버퍼 캐시 실제 크기 확인
SELECT component, current_size/1024/1024 AS size_mb
FROM v$sga_dynamic_components
WHERE component LIKE '%buffer cache%';

-- 버퍼 풀 통계 확인 (히트율)
SELECT name, block_size,
       1 - (physical_reads / NULLIF(db_block_gets + consistent_gets, 0)) AS hit_ratio
FROM v$buffer_pool_statistics
WHERE db_block_gets + consistent_gets > 0;

-- 16KB 블록 사이즈용 버퍼 캐시 할당
ALTER SYSTEM SET DB_16K_CACHE_SIZE = 64M;

-- 32KB 블록 사이즈용 버퍼 캐시 할당
ALTER SYSTEM SET DB_32K_CACHE_SIZE = 32M;

-- 16KB 블록 사이즈 테이블스페이스 생성
CREATE TABLESPACE ts_dw_16k
  DATAFILE '/u01/oradata/orcl26ai/ts_dw_16k01.dbf' SIZE 1G
  BLOCKSIZE 16K
  EXTENT MANAGEMENT LOCAL
  SEGMENT SPACE MANAGEMENT AUTO;

-- 32KB 블록 사이즈 테이블스페이스 생성
CREATE TABLESPACE ts_lob_32k
  DATAFILE '/u01/oradata/orcl26ai/ts_lob_32k01.dbf' SIZE 500M
  BLOCKSIZE 32K;

-- 비표준 블록 사이즈 캐시 설정 확인
SHOW PARAMETER db_16k_cache_size;
SHOW PARAMETER db_32k_cache_size;
